// Get forecast data for today and next 4 days
const forecasts = [];

// Get the detailed forecast sections
const forecastSections = document.querySelectorAll('.forecast-detailed-day');
if (forecastSections.length > 0) {
  forecastSections.forEach(section => {
    const dateHeading = section.querySelector('h2, h3, .date-heading');
    const summary = section.querySelector('.summary, .forecast-text');
    if (dateHeading && summary) {
      forecasts.push({
        date: dateHeading.textContent.trim(),
        forecast: summary.textContent.trim()
      });
    }
  });
}

// Try alternative structure - look for day headings and forecast text
if (forecasts.length === 0) {
  const dayElements = document.querySelectorAll('h2, h3');
  dayElements.forEach(heading => {
    const text = heading.textContent.trim();
    if (text.includes('Monday') || text.includes('Tuesday') || text.includes('Wednesday') || 
        text.includes('Thursday') || text.includes('Friday') || text.includes('Saturday') || 
        text.includes('Sunday')) {
      const nextP = heading.nextElementSibling;
      if (nextP) {
        forecasts.push({
          date: text,
          forecast: nextP.textContent.trim()
        });
      }
    }
  });
}

// Get text from the main forecast area
const mainContent = document.querySelector('main, .content, #content, .main-content');
return {
  forecasts: forecasts,
  fullText: mainContent ? mainContent.textContent : document.body.textContent
};

